```go
package cache

import (
	"container/list"
	"sync"
	"time"
)

type Cache struct {
	mu       sync.RWMutex
	entries  map[string]*list.Element
	lru      *list.List
	maxSize  int
	ttl      time.Duration
	quit     chan struct{}
	stats    CacheStats
	clock    func() time.Time
	evictCh  chan struct{}
}

// cache entry
type entry struct {
	key       string
	value     interface{}
	expiry    time.Time
	createdAt time.Time
}

// stats
type CacheStats struct {
	Hits   int64 `json:"hits"`
	Misses int64 `json:"misses"`
}

// New creates a new cache with given maxSize and ttl.
func New(maxSize int, ttl time.Duration) *Cache {
	c := &Cache{
		entries: make(map[string]*list.Element),
		lru:      list.New(),
		maxSize:  maxSize,
		ttl:      ttl,
		quit:     make(chan struct{}),
		clock:    time.Now,
	}
	if ttl > 0 {
		c.evictCh = make(chan struct{}, 1)
		go c.evictionLoop()
	}
	return c
}

// Set adds or updates a value in the cache.
func (c *Cache) Set(key string, value interface{}) {
	c.mu.Lock()
	defer c.mu.Unlock()

	if el, ok := c.entries[key]; ok {
		c.lru.MoveToFront(el)
		ent := el.Value.(*entry)
		ent.value = value
		ent.expiry = c.clock().Add(c.ttl)
		return
	}

	if c.maxSize > 0 && c.lru.Len() >= c.maxSize {
		c.evictOldest()
	}

	e := &entry{
		key:    key,
		value:  value,
		expiry: c.clock().Add(c.ttl),
	}
	el := c.lru.PushFront(e)
	c.entries[key] = el
}

// Get retrieves a value from the cache.
func (c *Cache) Get(key string) (interface{}, bool) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	if el, ok := c.entries[key]; ok {
		ent := el.Value.(*entry)
		if c.ttl > 0 && c.clock().After(ent.expiry) {
			// expired
			go c.delete(key) // async delete
			c.stats.Misses++
			return nil, false
		}
		c.lru.MoveToFront(el)
		c.stats.Hits++
		return ent.value, true
	}
	c.stats.Misses++
	return nil, false
}

// Delete removes a key from the cache.
func (c *Cache) Delete(key string) {
	c.mu.Lock()
	defer c.mu.Unlock()
	c.delete(key)
}

// internal delete without locking
func (c *Cache) delete(key string) {
	if el, ok := c.entries[key]; ok {
		c.lru.Remove(el)
		delete(c.entries, key)
	}
}

// Close stops background goroutine.
func (c *Cache) Close() {
	close(c.quit)
}

// evictionLoop runs periodic eviction.
func (c *Cache) evictionLoop() {
	ticker := time.NewTicker(c.ttl / 2)
	defer ticker.Stop()
	for {
		select {
		case <-ticker.C:
			c.evictExpired()
		case <-c.quit:
			return
		}
	}
}

// evictExpired removes expired entries.
func (c *Cache) evictExpired() {
	c.mu.Lock()
	defer c.mu.Unlock()
	for k, el := range c.entries {
		ent := el.Value.(*entry)
		if c.clock().After(ent.expiry) {
			c.lru.Remove(el)
			delete(c.entries, k)
		}
	}
}

// evictOldest removes the oldest entry.
func (c *Cache) evictOldest() {
	if c.lru.Len() == 0 {
		return
	}
	oldest := c.lru.Back()
	if oldest != nil {
		ent := oldest.Value.(*entry)
		c.lru.Remove(oldest)
		delete(c.entries, ent.key)
	}
}

// Stats returns cache statistics.
func (c *Cache) Stats() CacheStats {
	c.mu.RLock()
	defer c.mu.RUnlock()
	return c.stats
}
